class ContiguousKVPool:
    """Minimal simulator of a contiguous KV allocator (flat slab, no paging)."""

    def __init__(self, total_bytes: int, max_seq_len: int, bytes_per_token: int):
        self.total = total_bytes
        self.max_slot_bytes = max_seq_len * bytes_per_token
        # Simulate as a list of (start, size, occupied) tuples
        self.regions: list[tuple[int, int, bool]] = [(0, total_bytes, False)]

    def allocate(self, max_seq_len: int) -> int | None:
        """Try to allocate max_seq_len*bytes_per_token contiguous bytes. Returns start addr or None."""
        needed = self.max_slot_bytes
        for i, (start, size, used) in enumerate(self.regions):
            if not used and size >= needed:
                # Split region
                self.regions[i] = (start, needed, True)
                if size > needed:
                    self.regions.insert(i + 1, (start + needed, size - needed, False))
                return start
        return None  # external fragmentation — no contiguous block large enough

    def free(self, addr: int) -> None:
        for i, (start, size, used) in enumerate(self.regions):
            if start == addr and used:
                self.regions[i] = (start, size, False)
                self._coalesce()
                return

    def _coalesce(self):
        """Merge adjacent free regions (best-case: prevents some external fragmentation)."""
        merged = []
        for region in self.regions:
            if merged and not merged[-1][2] and not region[2]:
                prev = merged.pop()
                merged.append((prev[0], prev[1] + region[1], False))
            else:
                merged.append(region)
        self.regions = merged

    @property
    def largest_free_block(self) -> int:
        return max((size for _, size, used in self.regions if not used), default=0)

    @property
    def total_free(self) -> int:
        return sum(size for _, size, used in self.regions if not used)


# Simulate fragmentation building up
pool = ContiguousKVPool(
    total_bytes=24 * 1024**3,  # 24 GB
    max_seq_len=4096,
    bytes_per_token=32 * 2 * 128 * 2,  # 32 layers, 2 (K+V), 128 d_head, float16
)

allocs = []
for i in range(8):
    addr = pool.allocate(4096)
    if addr is not None:
        allocs.append(addr)
        print(f"Allocated slot {i}: addr={addr//1e9:.2f}GB  free={pool.total_free/1e9:.2f}GB")

# Free alternating slots → external fragmentation
for i in [0, 2, 4, 6]:
    pool.free(allocs[i])

print(f"\nAfter freeing even slots:")
print(f"  Total free:         {pool.total_free/1e9:.2f} GB")
print(f"  Largest contiguous: {pool.largest_free_block/1e9:.2f} GB")
ext_frag = 1 - pool.largest_free_block / pool.total_free
print(f"  External frag rate: {ext_frag*100:.1f}%")
# Shows: total_free ≈ 12GB but largest_contiguous ≈ 3GB → high external fragmentation
